(8, 'welcome', 'institusi', 'deskripsi', 'text', 'Bergabung bersama perguruan tinggi terbaik Indonesia dalam mewujudkan kampus berkarakter bela negara.', 2, '2026-06-11 09:52:41', '2026-06-11 09:52:41'),
