(13, 'welcome', 'timeline', 'daftar', 'repeater', '[{\"nomor\":\"01\",\"tanggal\":\"1 - 31 Agustus\",\"judul\":\"Registrasi & Validasi\",\"deskripsi\":\"Periode pendaftaran institusi dan verifikasi data PIC melalui portal Patriot Metric.\"},{\"nomor\":\"02\",\"tanggal\":\"1 Sep - 31 Okt\",\"judul\":\"Pengisian Rubrik\",\"deskripsi\":\"Periode pengisian rubrik penilaian dan unggah bukti pendukung oleh institusi.\"},{\"nomor\":\"03\",\"tanggal\":\"1 - 30 November\",\"judul\":\"Penilaian & Validasi\",\"deskripsi\":\"Tim penilai melakukan verifikasi dan kalkulasi skor pemeringkatan.\"},{\"nomor\":\"04\",\"tanggal\":\"17 Agustus\",\"judul\":\"Penghargaan\",\"deskripsi\":\"Pengumuman hasil dan upacara penghargaan nasional.\"}]', 3, '2026-06-11 09:52:41', '2026-06-11 09:52:41'),
