(24, 'profile', 'tujuan-utama', 'daftar', 'repeater', '[{\"nomor\":\"01\",\"judul\":\"Menjadi Instrumen\\nEvaluasi Pembinaan\\nKesadaran Bela Negara\",\"deskripsi\":\"Menilai sejauh mana upaya\\npembinaan karakter bela negara\\ntelah diinternalisasikan melalui\\nkebijakan dan program\\nperguruan tinggi.\"},{\"nomor\":\"02\",\"judul\":\"Memperkuat Ekosistem\\nPerguruan Tinggi Berbasis\\nNilai-nilai Bela Negara\",\"deskripsi\":\"Tercipta ekosistem perguruan\\ntinggi yang lebih kuat dalam\\nmenanamkan nilai-nilai bela\\nnegara dan tanggung jawab\\nsosial melalui berbagai aspek\\nTridharma Perguruan Tinggi.\"},{\"nomor\":\"03\",\"judul\":\"Mendorong Sinergi\\nAntar-Perguruan Tinggi\",\"deskripsi\":\"Perguruan Tinggi dapat saling\\nmemotivasi, bersama-sama\\nmembangun generasi muda\\nyang berdaya saing global,\\nadaptif, dan patriotik.\"}]', 3, '2026-06-11 09:52:41', '2026-06-11 09:52:41'),
(25, 'profile', 'manfaat-pemeringkatan', 'judul', 'text', 'Manfaat Pemeringkatan', 1, '2026-06-11 09:52:41', '2026-06-11 09:52:41'),
(26, 'profile', 'manfaat-pemeringkatan', 'daftar', 'repeater', '[{\"nomor\":\"01\",\"judul\":\"Meningkatkan Kesadaran Bela Negara\",\"deskripsi\":\"Mendorong Perguruan Tinggi untuk mewujudkan dan meningkatkan karakter bela negara.\"},{\"nomor\":\"02\",\"judul\":\"Membangun Jejaring dan Kolaborasi Nasional\",\"deskripsi\":\"Membuka peluang bagi perguruan tinggi peserta menjadi bagian dari jejaring Patriot Metric yang memungkinkan kolaborasi di tingkat nasional.\"},{\"nomor\":\"03\",\"judul\":\"Mendapatkan Pengakuan dan Reputasi\",\"deskripsi\":\"Meningkatkan citra dan reputasi perguruan tinggi sebagai kampus yang berkomitmen pada penguatan karakter bela negara.\"},{\"nomor\":\"04\",\"judul\":\"Mendorong Perubahan dan Aksi Sosial\",\"deskripsi\":\"Perguruan tinggi dapat melakukan perubahan karakter dalam segala aspek Tridharma Perguruan Tinggi.\"}]', 2, '2026-06-11 09:52:41', '2026-06-11 09:52:41'),
