(39, 'panduan', 'steps', 'daftar', 'repeater', '[{\"label\":\"Langkah 1\",\"judul\":\"Input Data\",\"deskripsi\":\"Peserta mengisi formulir pemeringkatan secara daring dan mengunggah dokumen pendukung.\",\"icon\":\"user-plus\"},{\"label\":\"Langkah 2\",\"judul\":\"Validasi\",\"deskripsi\":\"Proses validasi oleh Tim Evaluator untuk memastikan keabsahan data, termasuk wawancara & visitasi lapangan.\",\"icon\":\"file-check\"},{\"label\":\"Langkah 3\",\"judul\":\"Penilaian\",\"deskripsi\":\"Penilaian untuk setiap indikator berbentuk skor angka dan diolah secara statistik.\",\"icon\":\"trending-up\"},{\"label\":\"Langkah 4\",\"judul\":\"Pengumuman\",\"deskripsi\":\"Hasil akhir ditetapkan berdasarkan skor kumulatif dan disampaikan dalam bentuk peringkat bintang.\",\"icon\":\"check-circle\"}]', 1, '2026-06-11 09:52:41', '2026-06-11 09:52:41'),
(40, 'panduan', 'faq', 'judul', 'text', 'Tanya Jawab (FAQ)', 1, '2026-06-11 09:52:41', '2026-06-11 09:52:41'),
(41, 'panduan', 'faq', 'daftar', 'repeater', '[{\"pertanyaan\":\"Siapa yang berhak mendaftarkan institusi?\",\"jawaban\":\"Pendaftaran dapat dilakukan oleh perwakilan resmi (PIC) yang ditunjuk oleh rektorat atau pimpinan perguruan tinggi dengan melampirkan Surat Tugas resmi.\"},{\"pertanyaan\":\"Berapa lama proses validasi berlangsung?\",\"jawaban\":\"Proses validasi berlangsung selama 15 hari kerja setelah pendaftaran diterima dan dokumen dinyatakan lengkap.\"},{\"pertanyaan\":\"Apakah sistem ini berbayar?\",\"jawaban\":\"Tidak, sistem Patriot Metric sepenuhnya gratis dan terbuka untuk seluruh perguruan tinggi di Indonesia.\"}]', 2, '2026-06-11 09:52:41', '2026-06-11 09:52:41'),
(42, 'pengumuman', 'hero', 'judul', 'text', 'Pengumuman', 1, '2026-06-11 09:52:41', '2026-06-11 09:52:41'),
